import{_ as t,c as e,o as n,O as r}from"./chunks/framework.97fbe135.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"guide/replace-files-ios.md","lastUpdated":1716609381000}'),l={name:"guide/replace-files-ios.md"},a=r('<p>如果我们提供的安装包不符合你的口味，你也可以自行替换自己喜欢的美化包或者添加自己想要的修改，<strong>注意这里是ios篇教学</strong>。</p><ol><li><p>首先需要一台电脑，在你的电脑安装任意解压缩软件，推荐<a href="https://www.bandisoft.com/bandizip/" target="_blank" rel="noreferrer">Bandizip</a>，以下步骤将用Bandizip作为示例来讲解。</p></li><li><p>把ipa安装包和你需要替换的美化包或者xnb类mod放到电脑上。</p></li><li><p>右键点击ipa安装包，选择“打开方式”，然后弹出的窗口里选择用Bandizip打开，其他解压缩软件同理。</p></li><li><p>此时依次点击<strong>StardewValley.app-Content</strong>，在Content目录下即为可替换的游戏内容文件，每个文件夹对应不同的内容，结构如下：</p><table><thead><tr><th style="text-align:center;">文件名称</th><th style="text-align:center;">说明</th></tr></thead><tbody><tr><td style="text-align:center;">Animals</td><td style="text-align:center;">储存关于动物的相关文件</td></tr><tr><td style="text-align:center;">Buildings</td><td style="text-align:center;">储存关于建筑的相关文件</td></tr><tr><td style="text-align:center;">Characters</td><td style="text-align:center;">储存关于人物的相关文件，其中包括人物行走图，人物对话，主角行走图，主角衣服配饰，怪物行走图等内容</td></tr><tr><td style="text-align:center;">Data</td><td style="text-align:center;">储存关于游戏数据的相关文件，内容较多，具体可查看<a href="https://stardewvalleywiki.com/Modding:Index" target="_blank" rel="noreferrer">wiki</a></td></tr><tr><td style="text-align:center;">Effects</td><td style="text-align:center;">用不到</td></tr><tr><td style="text-align:center;">Fonts</td><td style="text-align:center;">储存关于游戏字体的相关文件</td></tr><tr><td style="text-align:center;">LooseSprites</td><td style="text-align:center;">储存关于界面UI的相关文件，其中还包括鱼类和鸟类的图标文件</td></tr><tr><td style="text-align:center;">Maps</td><td style="text-align:center;">储存关于地图的相关文件</td></tr><tr><td style="text-align:center;">Minigames</td><td style="text-align:center;">储存关于主界面UI的相关文件</td></tr><tr><td style="text-align:center;">Portraits</td><td style="text-align:center;">储存关于NPC肖像图的相关文件</td></tr><tr><td style="text-align:center;">Strings</td><td style="text-align:center;">储存关于系统提示的相关文件，一般用不到</td></tr><tr><td style="text-align:center;">TerrainFeatures</td><td style="text-align:center;">储存关于树木，地板，地块，花草等贴图的相关文件</td></tr><tr><td style="text-align:center;">TileSheets</td><td style="text-align:center;">储存关于家具，农作物，果树，武器，工具等贴图的相关文件</td></tr><tr><td style="text-align:center;">VolcanoLayouts</td><td style="text-align:center;">用不到</td></tr><tr><td style="text-align:center;">XACT</td><td style="text-align:center;">用不到</td></tr></tbody></table></li><li><p>知道了对应的文件夹放什么文件后，只需要把你需要替换的美化文件或者xnb类mod直接拖到对应的文件夹里即可。</p></li><li><p>一般美化或者xnb类mod作者都会事先把修改后的文件放在对应的文件夹里面，所以你下载的文件基本都是一个Content文件夹，替换的时候就很方便，直接拖动Content文件夹到ipa包里替换掉原来的Content文件夹就可以了。</p></li><li><p>为了体现真·保姆教程，以防替换错，你可以按照这个步骤来替换：看本教程的第3步，打开ipa包，点击StardewValley.app后你会看到有一个Content文件夹，<strong>不要点进去</strong>，直接把你要替换的Content文件夹拖动到压缩软件打开的窗口里，会提示“将文件添加到压缩包”，点击确定，然后会提示存在相同的文件，选择<strong>覆盖-应用到全部文件</strong>，点击确定，这样就替换完成了。</p></li><li><p>然后把你替换后的ipa包重新自签安装到手机就可以了，关于如何自签<a href="/guide/offline">请看这里</a>。</p></li></ol>',2),i=[a];function d(s,o,c,g,p,x){return n(),e("div",null,i)}const f=t(l,[["render",d]]);export{_ as __pageData,f as default};
